#include <bits/stdc++.h>
using namespace std;

class Node {
public:
   int data;
   Node* next;
   Node* prev;

   Node(int value) {
       data = value;
       next = nullptr;
       prev = nullptr;
   }
};

class DoublyLinkedList {
public:
   Node* head;

   DoublyLinkedList() : head(nullptr) {}

   void append(int data) {
       if (!head) {
           head = new Node(data);
       } else {
           Node* cur = head;
           while (cur->next) {
               cur = cur->next;
           }
           Node* new_node = new Node(data);
           cur->next = new_node;
           new_node->prev = cur;
       }
   }

   void print_forward() {
       Node* cur = head;
       while (cur) {
           cout << cur->data << ' ';
           cur = cur->next;
       }
       cout << endl;
   }

   void print_backward() {
       Node* cur = head;
       if (cur == nullptr) {
           return;
       }
       while (cur->next) {
           cur = cur->next;
       }
       while (cur) {
           cout << cur->data << ' ';
           cur = cur->prev;
       }
       cout << endl;
   }
};

int main() {
   int n;
   if (!(cin >> n)) return 0;
   vector<int> nums(n);
   for (int i = 0; i < n; i++) cin >> nums[i];

   DoublyLinkedList dll;
   for (int num : nums) {
       dll.append(num);
   }

   dll.print_forward();
   dll.print_backward();

   return 0;
}
